// Developer note: Do not edit this file directly unless necessary.

export type Role = 'CLIENT' | 'LAWYER' | 'COURT_ADMIN' | 'ADMIN' | 'ORGANIZATION';

export interface User {
  id: string;
  name: string;
  email: string;
  phone: number;
  role: Role;
  avatar?: string;
  /** Present when role === 'ORGANIZATION' (decoded from JWT). */
  organizationId?: string | null;
}

// ── Organization (Law Firm) ────────────────────────────────────────────

export type OrgAppointmentRequestStatus =
  | 'PENDING'
  | 'ASSIGNED'
  | 'REJECTED'
  | 'CANCELLED'
  | 'EXPIRED'

export interface Organization {
  id: string
  name: string
  email: string
  phone: string
  avatarUrl?: string | null
  isVerified: boolean
  emailVerified: boolean
  registrationNumber?: string | null
  registrationCertUrl?: string | null
  gstNumber?: string | null
  gstProofUrl?: string | null
  panNumber?: string | null
  about?: string | null
  website?: string | null
  practiceAreas: string[]
  /** PAISE — divide by 100 for display. */
  consultationFee?: number | null
  country?: string
  state?: string
  district?: string
  city?: string
  pincode?: string
  address?: string
  latitude?: number | null
  longitude?: number | null
  createdAt: string
  updatedAt: string
}

export interface VerifiedLawyer {
  id: string
  name: string
  email?: string
  phone?: string
  avatarUrl?: string | null
  licenseNumber?: string | null
  barCouncilId?: string | null
  specializations?: string[]
  feePerConsultation?: number | null
  pincode?: string | null
  city?: string | null
  state?: string | null
  bio?: string | null
  experienceYears?: number | null
  isVerified?: boolean
}

export interface OrgAppointmentRequest {
  id: string
  organizationId: string
  clientId: string
  scheduledAt: string
  durationMins: number
  meetingType: 'AUDIO_CALL' | 'VIDEO_CALL' | 'OFFICE_VISIT' | null
  notes?: string | null
  status: OrgAppointmentRequestStatus
  rejectionReason?: string | null
  assignedLawyerId?: string | null
  appointmentId?: string | null
  organization: {
    id: string
    name: string
    avatarUrl?: string | null
    consultationFee?: number | null
    pincode?: string | null
    city?: string | null
    state?: string | null
  }
  client: {
    id: string
    name: string
    email: string
    phone: string
    avatarUrl?: string | null
  }
  assignedLawyer?: {
    id: string
    name: string
    email: string
    avatarUrl?: string | null
  } | null
  appointment?: {
    id: string
    status: string
    scheduledAt: string
    paymentId?: string | null
  } | null
  createdAt: string
  updatedAt: string
}

export interface OrgVerificationRequest {
  id: string
  organizationId: string
  courtAdminId: string
  status: 'PENDING' | 'APPROVED' | 'REJECTED'
  remarks?: string | null
  verifiedAt?: string | null
  createdAt: string
  organization: Organization
}

export interface Lawyer {
  id: string;
  name: string;
  specialization: string[];
  experienceYears: number;
  rating: number;
  fee: number;
  location: string;
  languages: string[];
  avatar?: string;
  isVerified?: boolean;
  reviewsCount?: number;
  distance?: number; // km — only present in geo search
}

export interface Appointment {
  id: string;
  lawyerId: string;
  clientId: string;
  datetime: string;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled' | 'rejected';
  paymentId?: string;
}

export interface Case {
  id: string;
  title: string;
  clientId: string;
  lawyerId: string;
  status: string;
  createdAt: string;
  updatedAt: string;
}

export interface Document {
  id: string;
  caseId: string;
  name: string;
  url: string;
  uploadedBy: string;
  uploadedAt: string;
  type: string;
}

export interface ChatMessage {
  id: string;
  chatId: string;
  senderId: string;
  text: string;
  attachments?: string[];
  createdAt: string;
  readAt?: string;
}

export interface TimelineEvent {
  id: string;
  title: string;
  date: string;
  description?: string;
  type: 'hearing' | 'task' | 'document';
}

export interface AgreementTemplate {
  id: string
  lawyerId: string
  title: string
  description?: string
  content: string
  category?: string
  isDefault: boolean
  createdAt: string
  updatedAt: string
}

export type TransactionType = 'CREDIT' | 'DEBIT' | 'WITHDRAWAL' | 'REFUND' | 'PAYMENT' | 'TRANSFER'
export type TransactionStatus = 'COMPLETED' | 'FAILED'

export interface WalletTransaction {
  id: string
  walletId: string
  userId: string
  amount: number
  type: TransactionType
  status: TransactionStatus
  description: string
  referenceId?: string | null
  counterpartyId?: string | null
  bankAccountId?: string | null
  createdAt: string
}

// ── Push Notifications ───────────────────────────────────────────────

export type NotificationType =
  | 'APPOINTMENT_BOOKED'
  | 'APPOINTMENT_CONFIRMED'
  | 'APPOINTMENT_CANCELLED'
  | 'APPOINTMENT_REMINDER'
  | 'APPOINTMENT_RESCHEDULED'
  | 'NEW_MESSAGE'
  | 'PAYMENT_RECEIVED'
  | 'WALLET_CREDIT'
  | 'WALLET_DEBIT'
  | 'CONSULTATION_COMPLETED'
  | 'REVIEW_RECEIVED'
  | 'CASE_UPDATE'
  | 'DOCUMENT_UPLOADED'
  | 'VIDEO_CALL'
  | 'TASK_ASSIGNED'
  // Organization (law-firm) flow
  | 'ORGANIZATION_VERIFIED'
  | 'ORGANIZATION_REJECTED'
  | 'ORG_APPOINTMENT_REQUEST_RECEIVED'
  | 'ORG_APPOINTMENT_REQUEST_ASSIGNED'
  | 'ORG_APPOINTMENT_REQUEST_REJECTED'

export interface NotificationData {
  appointmentId?: string
  chatId?: string
  caseId?: string
  referenceId?: string
  // Organization-flow extras
  requestId?: string
  paymentId?: string
  organizationId?: string
  lawyerId?: string
}

export interface Notification {
  id: string
  userId?: string
  title: string
  body: string
  type: NotificationType
  data: NotificationData
  isRead: boolean
  readAt?: string | null
  createdAt: string
}

export interface NotificationListResponse {
  items: Notification[]
  total: number
  unreadCount: number
  page: number
  limit: number
}